@app.route('/api/apply',methods=['POST'])
def api_apply():
	data=request.get_json(force=True)or{};patch_text=data.get('patch_text','')
	if not isinstance(patch_text,str):patch_text=''
	folder=(data.get('folder')or'').strip();dry_run=data.get('dry_run',False)
	if not patch_text.strip():return jsonify(ok=False,error='Patch masih kosong.'),400
	with JOB_LOCK:
		if CURRENT_JOB[0]is not None and not CURRENT_JOB[0].done:return jsonify(ok=False,error='Masih ada proses lain berjalan, tunggu sampai selesai.'),409
	if folder:
		if any(keyword in folder for keyword in[':file',':find',':replace',':title']):return jsonify(ok=False,error='Input folder salah. Sepertinya Anda menempelkan patch ke kolom folder.'),400
		folder_abs=os.path.abspath(os.path.expanduser(folder))
		if not os.path.isdir(folder_abs):return jsonify(ok=False,error=f'Folder "{folder}" tidak ditemukan atau bukan folder yang valid.'),400
		frtool.SOURCE_ROOT=folder_abs
	job=Job();JOBS[job.id]=job;CURRENT_JOB[0]=job;t=threading.Thread(target=_run_job,args=(job,patch_text,dry_run),daemon=True);job.thread=t;t.start();return jsonify(ok=True,job_id=job.id,source_root=frtool.SOURCE_ROOT)
@app.route('/api/stream/<job_id>')
def api_stream(job_id):
	job=JOBS.get(job_id)
	if job is None:return'job tidak ditemukan',404
	def gen():
		while True:
			item=job.out_q.get();yield f"data: {json.dumps(item)}\n\n"
			if item.get('type')=='done':break
	return Response(gen(),mimetype='text/event-stream',headers={'Cache-Control':'no-cache','X-Accel-Buffering':'no'})
