	if'api_key_add'in data:
		new_key=(data['api_key_add']or'').strip();existing=cfg.get(f"api_key_{prov}",cfg.get('api_key',''));keys=[k.strip()for k in existing.split(',')if k.strip()]
		if new_key and new_key not in keys:keys.append(new_key)
		cfg[f"api_key_{prov}"]=','.join(keys);cfg['api_key']=cfg[f"api_key_{prov}"]
	if'api_key_remove'in data:
		idx=int(data['api_key_remove']);existing=cfg.get(f"api_key_{prov}",cfg.get('api_key',''));keys=[k.strip()for k in existing.split(',')if k.strip()]
		if 0<=idx<len(keys):keys.pop(idx)
		cfg[f"api_key_{prov}"]=','.join(keys);cfg['api_key']=cfg[f"api_key_{prov}"]
	frtool.save_ai_config(cfg);return api_ai_config_get()
